/**
 * @summary List scenarios for all cases
 */
export const getListScenariosUrl = (params?: ListScenariosParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/scenarios?${stringifiedParams}`
    : `/api/scenarios`;
};

export const listScenarios = async (
  params?: ListScenariosParams,
  options?: RequestInit,
): Promise<Scenario[]> => {
  return customFetch<Scenario[]>(getListScenariosUrl(params), {
    ...options,
    method: "GET",
  });
};

